/**
 * 이미지 버튼의 Enable/Disable
 */
scwin.f_ToggleImgBtn = function (mode) {

    if (mode) {
        grp_deptInfo.setDisabled(false);

        $c.gus.cfEnableObjects([ed_adptStDt, ed_adptEndDt]);
        $c.gus.cfEnableObjects([ed_upperAcctDeptCd, ed_upperAcctDeptNm, btn_upperAcctDept]);
        $c.gus.cfEnableObjects([ed_budgetCntlAcctDeptCd, ed_budgetCntlAcctDeptNm, btn_budgetCntlAcctDept]);
        $c.gus.cfEnableObjects([ed_vatDeclarAcctDeptCd, ed_vatDeclarAcctDeptNm, btn_vatDeclarAcctDept]);
        $c.gus.cfEnableObjects([ed_advcdExecAcctDeptCd, ed_advcdExecAcctDeptNm, btn_advcdExecAcctDept]);
        $c.gus.cfEnableObjects([ed_fundExecAcctDeptCd, ed_fundExecAcctDeptNm, btn_fundExecAcctDept]);
        $c.gus.cfEnableObjects([ed_withholdDofficeCd, ed_withholdDofficeNm, btn_withholdDoffice]);
        $c.gus.cfEnableObjects([ed_asetAcctDeptCd, ed_asetAcctDeptNm, btn_asetAcctDeptCd]);
        $c.gus.cfEnableObjects([ed_mgntPrfLossAggrDeptCd, ed_mgntPrfLossAggrDeptNm, btn_mgntPrfLossAggrDept]);
        $c.gus.cfEnableObjects([ed_branchAggrDeptCd, ed_branchAggrDeptNm, btn_branchAggrDept]);
        $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        // $c.gus.cfEnableObjects([lc_coClsCd]);
        // $c.gus.cfEnableObjects([chb_virtureDeptYn]);
    } else {
        grp_deptInfo.setDisabled(true);

        $c.gus.cfDisableObjects([ed_adptStDt, ed_adptEndDt]);
        $c.gus.cfDisableObjects([ed_upperAcctDeptCd, ed_upperAcctDeptNm, btn_upperAcctDept]);
        $c.gus.cfDisableObjects([ed_budgetCntlAcctDeptCd, ed_budgetCntlAcctDeptNm, btn_budgetCntlAcctDept]);
        $c.gus.cfDisableObjects([ed_vatDeclarAcctDeptCd, ed_vatDeclarAcctDeptNm, btn_vatDeclarAcctDept]);
        $c.gus.cfDisableObjects([ed_advcdExecAcctDeptCd, ed_advcdExecAcctDeptNm, btn_advcdExecAcctDept]);
        $c.gus.cfDisableObjects([ed_fundExecAcctDeptCd, ed_fundExecAcctDeptNm, btn_fundExecAcctDept]);
        $c.gus.cfDisableObjects([ed_withholdDofficeCd, ed_withholdDofficeNm, btn_withholdDoffice]);
        $c.gus.cfDisableObjects([ed_asetAcctDeptCd, ed_asetAcctDeptNm, btn_asetAcctDeptCd]);
        $c.gus.cfDisableObjects([ed_mgntPrfLossAggrDeptCd, ed_mgntPrfLossAggrDeptNm, btn_mgntPrfLossAggrDept]);
        $c.gus.cfDisableObjects([ed_branchAggrDeptCd, ed_branchAggrDeptNm, btn_branchAggrDept]);
        $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        // $c.gus.cfDisableObjects([lc_coClsCd]);
        // $c.gus.cfDisableObjects([chb_virtureDeptYn]);
    }

    // 자회사여부, 자회사구분
    chb_virtureDeptYn.setDisabled(true);
    lc_coClsCd.setDisabled(true);
};
